export function getTomeGeneratedCoverPaths(bookId: string): TomeGeneratedCoverPaths | undefined {
  const monumentalAssets = getMonumentalLiteraryPathsAssets(bookId)
  if (monumentalAssets) {
    return {
      image: monumentalAssets.coverMaster2x3,
      thumbnail: monumentalAssets.coverThumbnail,
      source: monumentalAssets.coverMaster2x3,
    }
  }

  // Cover cull (2026-06-18): the previous custom-designed Tome covers were
  // archived to archive/covers/tome-generated. The legacy data map above is
  // retained for reversibility, but only approved Monumental Literary Paths
  // packs are exposed to the live app.
  return undefined
}
